SELECT n.id, p.country_code, p.rank, 2024
FROM n JOIN (VALUES
  ('Gigi','GE',500),
  ('Teo','GE',501)
) AS p(name, country_code, rank) ON n.name = p.name
ON CONFLICT (name_id, country_code) DO NOTHING;

