WITH n AS (SELECT id, name FROM names_db WHERE gender = 'neutral')
INSERT INTO name_popularity (name_id, country_code, popularity_rank, year)
SELECT n.id, p.country_code, p.rank, 2024
FROM n JOIN (VALUES
  ('Alex','PT',500),
  ('Amor','PT',501),
  ('Carmo','PT',502),
